{"content":"import type { NextApiRequest, NextApiResponse } from "next";
import { readFileSync, writeFileSync, existsSync } from "fs";
import { join } from "path";

const WEEK_PATH = join(process.cwd(), "content", "active-week.json");

function readWeek() {
  if (!existsSync(WEEK_PATH)) {
    return {
      label: "Semana del 13 al 18 mayo",
      option_a: "bolognese",
      option_b: "pollo-pepitoria",
      option_c: "lentejas",
      extra: "crema-zapallo",
    };
  }
  return JSON.parse(readFileSync(WEEK_PATH, "utf-8"));
}

function writeWeek(data: unknown) {
  writeFileSync(WEEK_PATH, JSON.stringify(data, null, 2), "utf-8");
}

export default function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method === "GET") {
    res.status(200).json(readWeek());
  } else if (req.method === "PUT") {
    try {
      const updated = { ...readWeek(), ...req.body, last_updated: new Date().toISOString().split("T")[0] };
      writeWeek(updated);
      res.status(200).json({ ok: true, week: readWeek() });
    } catch {
      res.status(500).json({ error: "Failed to save week" });
    }
  } else {
    res.setHeader("Allow", "GET, PUT");
    res.status(405).end();
  }
}","path":"/root/sites/meal-prep-website/pages/api/menu/week.ts"}

{"content":"import type { NextApiRequest, NextApiResponse } from "next";
import { readFileSync, writeFileSync, existsSync } from "fs";
import { join } from "path";
import content from "@/content/menu-content.json";

const CATALOG_PATH = join(process.cwd(), "content", "menu-content.json");

function readCatalog() {
  if (existsSync(CATALOG_PATH)) {
    const full = JSON.parse(readFileSync(CATALOG_PATH, "utf-8"));
    return full.catalog || [];
  }
  return content.catalog || [];
}

export default function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method === "GET") {
    res.status(200).json({ catalog: readCatalog() });
  } else {
    res.setHeader("Allow", "GET");
    res.status(405).end();
  }
}","path":"/root/sites/meal-prep-website/pages/api/menu/catalog.ts"}

